use headless_chrome::{Browser, LaunchOptions};
use std::error::Error;

fn main() -> Result<(), Box<dyn Error>> {
    let chrome_path = std::env::var("CHROME_BIN").ok().map(std::path::PathBuf::from);
    let browser = Browser::new(LaunchOptions {
        headless: true,
        sandbox: false,
        path: chrome_path,
        args: vec![
            std::ffi::OsStr::new("--no-sandbox"),
            std::ffi::OsStr::new("--disable-gpu"),
            std::ffi::OsStr::new("--disable-dev-shm-usage"),
            std::ffi::OsStr::new("--allow-file-access-from-files"),
        ],
        ..Default::default()
    })?;
    let tab = browser.new_tab()?;
    tab.navigate_to("file:///var/www/solana.solfunmeme.com/erdfa/index.html")?;
    tab.wait_until_navigated()?;
    std::thread::sleep(std::time::Duration::from_secs(3));

    // Generate 256x256 carrier
    tab.evaluate(r#"
        new Promise((resolve) => {
            const c = document.createElement('canvas');
            c.width = 256; c.height = 256;
            const ctx = c.getContext('2d');
            for (let y = 0; y < 256; y++) for (let x = 0; x < 256; x++) {
                ctx.fillStyle = `rgb(${x},${(x+y)%256},${y})`;
                ctx.fillRect(x, y, 1, 1);
            }
            const img = document.getElementById('carrier-preview');
            img.onload = () => resolve('ok');
            img.src = c.toDataURL('image/png');
        })
    "#, true)?;

    // Encode meme with stego
    let data_url = tab.evaluate(r#"
        (function() {
            document.getElementById('meme-top').value = 'SNEAKERNET';
            document.getElementById('meme-bot').value = 'ENCODE ALL THE THINGS';
            document.getElementById('input').value = 'meme test!';
            doStegoEnc();
            return document.getElementById('stego-canvas').toDataURL('image/png');
        })()
    "#, false)?;

    let url_str = data_url.value.unwrap_or_default().to_string();
    let url_str = url_str.trim_matches('"');
    let b64 = url_str.strip_prefix("data:image/png;base64,").unwrap_or("");
    let bytes = base64_decode(b64);
    std::fs::write("/tmp/erdfa-meme.png", &bytes)?;
    println!("Saved /tmp/erdfa-meme.png ({} bytes)", bytes.len());
    Ok(())
}

fn base64_decode(input: &str) -> Vec<u8> {
    let mut out = Vec::new();
    let lut: Vec<u8> = (0..256u16).map(|i| {
        let c = i as u8;
        match c {
            b'A'..=b'Z' => c - b'A',
            b'a'..=b'z' => c - b'a' + 26,
            b'0'..=b'9' => c - b'0' + 52,
            b'+' => 62, b'/' => 63,
            _ => 255,
        }
    }).collect();
    let chars: Vec<u8> = input.bytes().filter(|&b| lut[b as usize] != 255).collect();
    for chunk in chars.chunks(4) {
        if chunk.len() < 2 { break; }
        let a = lut[chunk[0] as usize] as u32;
        let b = lut[chunk[1] as usize] as u32;
        out.push(((a << 2) | (b >> 4)) as u8);
        if chunk.len() > 2 { let c = lut[chunk[2] as usize] as u32; out.push(((b << 4) | (c >> 2)) as u8);
            if chunk.len() > 3 { let d = lut[chunk[3] as usize] as u32; out.push(((c << 6) | d) as u8); }
        }
    }
    out
}

