fn base64_decode(input: &str) -> Vec<u8> {
    let mut out = Vec::new();
    let lut: Vec<u8> = (0..256u16).map(|i| {
        let c = i as u8;
        match c {
            b'A'..=b'Z' => c - b'A',
            b'a'..=b'z' => c - b'a' + 26,
            b'0'..=b'9' => c - b'0' + 52,
            b'+' => 62, b'/' => 63,
            _ => 255,
        }
    }).collect();
    let chars: Vec<u8> = input.bytes().filter(|&b| lut[b as usize] != 255).collect();
    for chunk in chars.chunks(4) {
        if chunk.len() < 2 { break; }
        let a = lut[chunk[0] as usize] as u32;
        let b = lut[chunk[1] as usize] as u32;
        out.push(((a << 2) | (b >> 4)) as u8);
        if chunk.len() > 2 { let c = lut[chunk[2] as usize] as u32; out.push(((b << 4) | (c >> 2)) as u8);
            if chunk.len() > 3 { let d = lut[chunk[3] as usize] as u32; out.push(((c << 6) | d) as u8); }
        }
    }
    out
}

