// ALife parameter search for DCT steganography
// Evolves QIM_STEP to survive JPEG compression while minimizing visual distortion
// Based on hecke_alife.rs pattern

use std::collections::HashMap;

// --- DCT stego core (copied from lib.rs, parameterized) ---

fn dct8(x: &[f32; 8]) -> [f32; 8] {
    let mut y = [0.0f32; 8];
    for k in 0..8 {
        let ck = if k == 0 { (1.0 / 8.0f32).sqrt() } else { (2.0 / 8.0f32).sqrt() };
        let mut s = 0.0;
        for n in 0..8 {
            s += x[n] * (std::f32::consts::PI * (2 * n + 1) as f32 * k as f32 / 16.0).cos();
        }
        y[k] = ck * s;
    }
    y
}

fn idct8(y: &[f32; 8]) -> [f32; 8] {
    let mut x = [0.0f32; 8];
    for n in 0..8 {
        let mut s = 0.0;
        for k in 0..8 {
            let ck = if k == 0 { (1.0 / 8.0f32).sqrt() } else { (2.0 / 8.0f32).sqrt() };
            s += ck * y[k] * (std::f32::consts::PI * (2 * n + 1) as f32 * k as f32 / 16.0).cos();
        }
        x[n] = s;
    }
    x
}

fn dct2d(block: &[[f32; 8]; 8]) -> [[f32; 8]; 8] {
    let mut tmp = [[0.0f32; 8]; 8];
    for r in 0..8 { tmp[r] = dct8(&block[r]); }
    let mut out = [[0.0f32; 8]; 8];
    for c in 0..8 {
        let mut col = [0.0f32; 8];
        for r in 0..8 { col[r] = tmp[r][c]; }
        let dc = dct8(&col);
        for r in 0..8 { out[r][c] = dc[r]; }
    }
    out
}

fn idct2d(block: &[[f32; 8]; 8]) -> [[f32; 8]; 8] {
    let mut tmp = [[0.0f32; 8]; 8];
    for c in 0..8 {
        let mut col = [0.0f32; 8];
        for r in 0..8 { col[r] = block[r][c]; }
        let ic = idct8(&col);
        for r in 0..8 { tmp[r][c] = ic[r]; }
    }
    let mut out = [[0.0f32; 8]; 8];
    for r in 0..8 { out[r] = idct8(&tmp[r]); }
    out
}

const EMBED_POS: [(usize, usize); 4] = [(1,2), (2,1), (2,2), (3,1)];
const REDUNDANCY: usize = 7;

fn qim_embed(coeff: f32, bit: u8, step: f32) -> f32 {
    let q = (coeff / step).round() as i32;
    let target = if (q & 1) as u8 == bit { q } else if coeff >= q as f32 * step { q + 1 } else { q - 1 };
    target as f32 * step
}

fn qim_extract(coeff: f32, step: f32) -> u8 {
    ((coeff / step).round() as i32 & 1) as u8
}

fn ecc_encode(data: &[u8]) -> Vec<u8> {
    let mut bits = Vec::new();
    for byte in data {
        for i in (0..8).rev() {
            let bit = (byte >> i) & 1;
            for _ in 0..REDUNDANCY { bits.push(bit); }
        }
    }
    bits
}

fn ecc_decode(bits: &[u8], num_bytes: usize) -> Vec<u8> {
    let mut out = Vec::new();
    for byte_i in 0..num_bytes {
        let mut byte = 0u8;
        for bit_i in 0..8 {
            let start = (byte_i * 8 + bit_i) * REDUNDANCY;
            let ones: u8 = (0..REDUNDANCY).map(|r| if start + r < bits.len() { bits[start + r] } else { 0 }).sum();
            if ones > (REDUNDANCY / 2) as u8 { byte |= 1 << (7 - bit_i); }
        }
        out.push(byte);
    }
    out
}

fn stego_encode(data: &[u8], carrier: &[u8], w: usize, h: usize, qim_step: f32) -> Vec<u8> {
    let bx = w / 8;
    let by = h / 8;
    let capacity = (bx * by * EMBED_POS.len()) / REDUNDANCY / 8;
    let mut payload = Vec::new();
    let len = data.len().min(capacity.saturating_sub(4)) as u32;
    payload.extend_from_slice(&len.to_be_bytes());
    payload.extend_from_slice(&data[..len as usize]);
    let ecc_bits = ecc_encode(&payload);

    let mut green = vec![0.0f32; w * h];
    for i in 0..w * h {
        green[i] = if i * 4 + 1 < carrier.len() { carrier[i * 4 + 1] as f32 } else { 128.0 };
    }

    let mut bit_idx = 0;
    for by_i in 0..by {
        for bx_i in 0..bx {
            let mut block = [[0.0f32; 8]; 8];
            for r in 0..8 { for c in 0..8 { block[r][c] = green[(by_i * 8 + r) * w + bx_i * 8 + c]; } }
            let mut dct = dct2d(&block);
            for &(er, ec) in &EMBED_POS {
                if bit_idx < ecc_bits.len() {
                    dct[er][ec] = qim_embed(dct[er][ec], ecc_bits[bit_idx], qim_step);
                    bit_idx += 1;
                }
            }
            let out = idct2d(&dct);
            for r in 0..8 { for c in 0..8 {
                green[(by_i * 8 + r) * w + bx_i * 8 + c] = out[r][c];
            }}
        }
    }

    let mut result = carrier.to_vec();
    if result.len() < w * h * 4 { result.resize(w * h * 4, 0); }
    for i in 0..w * h {
        result[i * 4 + 1] = green[i].round().clamp(0.0, 255.0) as u8;
    }
    result
}

fn stego_decode(pixels: &[u8], w: usize, h: usize, qim_step: f32) -> Vec<u8> {
    let bx = w / 8;
    let by = h / 8;
    let mut green = vec![0.0f32; w * h];
    for i in 0..w * h {
        green[i] = if i * 4 + 1 < pixels.len() { pixels[i * 4 + 1] as f32 } else { 128.0 };
    }
    let mut bits = Vec::new();
    for by_i in 0..by {
        for bx_i in 0..bx {
            let mut block = [[0.0f32; 8]; 8];
            for r in 0..8 { for c in 0..8 { block[r][c] = green[(by_i * 8 + r) * w + bx_i * 8 + c]; } }
            let dct = dct2d(&block);
            for &(er, ec) in &EMBED_POS { bits.push(qim_extract(dct[er][ec], qim_step)); }
        }
    }
    let len_bits = &bits[..std::cmp::min(32 * REDUNDANCY, bits.len())];
    let len_bytes = ecc_decode(len_bits, 4);
    let len = u32::from_be_bytes([len_bytes[0], len_bytes[1], len_bytes[2], len_bytes[3]]) as usize;
    let capacity = (bx * by * EMBED_POS.len()) / REDUNDANCY / 8;
    if len == 0 || len > capacity { return Vec::new(); }
    ecc_decode(&bits[32 * REDUNDANCY..], len)
}

// --- JPEG simulation (simple quantization model) ---

fn jpeg_simulate(pixels: &[u8], w: usize, h: usize, quality: u8) -> Vec<u8> {
    // Simulate JPEG by applying DCT quantization to all channels
    let q_scale = if quality >= 50 { 200 - 2 * quality as u16 } else { 5000 / quality as u16 };
    // Standard JPEG luminance quantization table
    let base_qtable: [u16; 64] = [
        16,11,10,16,24,40,51,61, 12,12,14,19,26,58,60,55,
        14,13,16,24,40,57,69,56, 14,17,22,29,51,87,80,62,
        18,22,37,56,68,109,103,77, 24,35,55,64,81,104,113,92,
        49,64,78,87,103,121,120,101, 72,92,95,98,112,100,103,99,
    ];
    let mut qtable = [0u16; 64];
    for i in 0..64 {
        qtable[i] = ((base_qtable[i] as u32 * q_scale as u32 + 50) / 100).clamp(1, 255) as u16;
    }

    let mut result = pixels.to_vec();
    if result.len() < w * h * 4 { result.resize(w * h * 4, 0); }

    for ch in 0..3 {
        let mut channel = vec![0.0f32; w * h];
        for i in 0..w * h { channel[i] = result[i * 4 + ch] as f32; }

        for by in 0..h / 8 {
            for bx in 0..w / 8 {
                let mut block = [[0.0f32; 8]; 8];
                for r in 0..8 { for c in 0..8 { block[r][c] = channel[(by * 8 + r) * w + bx * 8 + c] - 128.0; } }
                let mut dct = dct2d(&block);
                for r in 0..8 { for c in 0..8 {
                    let qi = qtable[r * 8 + c] as f32;
                    dct[r][c] = (dct[r][c] / qi).round() * qi;
                }}
                let out = idct2d(&dct);
                for r in 0..8 { for c in 0..8 {
                    channel[(by * 8 + r) * w + bx * 8 + c] = (out[r][c] + 128.0).clamp(0.0, 255.0);
                }}
            }
        }

        for i in 0..w * h { result[i * 4 + ch] = channel[i].round() as u8; }
    }
    result
}

// --- ALife organism: a stego parameter set ---

#[derive(Debug, Clone)]
struct Organism {
    id: u64,
    qim_step: f32,
    energy: f64,       // fitness score
    generation: u32,
}

impl Organism {
    fn new(id: u64, qim_step: f32) -> Self {
        Self { id, qim_step, energy: 0.0, generation: 0 }
    }

    fn evaluate(&mut self, carrier: &[u8], w: usize, h: usize) {
        let msg = b"alife stego parameter search test!";
        let encoded = stego_encode(msg, carrier, w, h, self.qim_step);

