        // + penalty for visual distortion
        let mut score = 0.0;

        for &q in &[95, 90, 85, 80, 75, 70, 65, 60, 55, 50, 45, 40] {
            let compressed = jpeg_simulate(&encoded, w, h, q);
            let decoded = stego_decode(&compressed, w, h, self.qim_step);
            if decoded == msg {
