        let mut mse = 0.0;
        for i in 0..w * h {
            let orig = carrier[i * 4 + 1] as f64;
            let steg = encoded[i * 4 + 1] as f64;
            mse += (orig - steg) * (orig - steg);
        }
        mse /= (w * h) as f64;
        score -= mse * 0.1; // small penalty for distortion

        self.energy = score;
    }

    fn reproduce(&self, other: &Organism, id: u64) -> Organism {
