            id,
            qim_step: child_step,
            energy: 0.0,
            generation: self.generation.max(other.generation) + 1,
        }
    }
}

fn make_carrier(w: usize, h: usize) -> Vec<u8> {
    let mut pixels = vec![0u8; w * h * 4];
