// JPEG simulation via DCT quantization
fn jpeg_simulate(pixels: &[u8], w: usize, h: usize, quality: u8) -> Vec<u8> {
    let q_scale = if quality >= 50 { 200 - 2 * quality as u16 } else { 5000 / quality as u16 };
    let base_q: [u16; 64] = [
        16,11,10,16,24,40,51,61, 12,12,14,19,26,58,60,55,
        14,13,16,24,40,57,69,56, 14,17,22,29,51,87,80,62,
        18,22,37,56,68,109,103,77, 24,35,55,64,81,104,113,92,
        49,64,78,87,103,121,120,101, 72,92,95,98,112,100,103,99,
    ];
    let qt: Vec<u16> = base_q.iter().map(|&v| ((v as u32 * q_scale as u32 + 50) / 100).clamp(1, 255) as u16).collect();
    let mut result = pixels.to_vec();
    if result.len() < w * h * 4 { result.resize(w * h * 4, 0); }
    for ch in 0..3 {
        let mut chan: Vec<f32> = (0..w*h).map(|i| result[i*4+ch] as f32).collect();
        for by in 0..h/8 { for bx in 0..w/8 {
            let mut bl = [[0.0f32; 8]; 8];
            for r in 0..8 { for c in 0..8 { bl[r][c] = chan[(by*8+r)*w+bx*8+c] - 128.0; } }
            let mut d = dct2d(&bl);
            for r in 0..8 { for c in 0..8 { let q = qt[r*8+c] as f32; d[r][c] = (d[r][c]/q).round()*q; } }
            let o = idct2d(&d);
            for r in 0..8 { for c in 0..8 { chan[(by*8+r)*w+bx*8+c] = (o[r][c]+128.0).clamp(0.0, 255.0); } }
        }}
        for i in 0..w*h { result[i*4+ch] = chan[i].round() as u8; }
    }
    result
}

// Parameterized stego encode/decode for ALife search
fn stego_encode_step(data: &[u8], carrier: &[u8], w: usize, h: usize, step: f32) -> Vec<u8> {
    let bx = w/8; let by = h/8;
    let cap = (bx*by*EMBED_POS.len())/STEGO_REDUNDANCY/8;
    let mut payload = Vec::new();
    let len = data.len().min(cap.saturating_sub(4)) as u32;
    payload.extend_from_slice(&len.to_be_bytes());
    payload.extend_from_slice(&data[..len as usize]);
    let bits = ecc_encode(&payload);
    let mut green: Vec<f32> = (0..w*h).map(|i| if i*4+1 < carrier.len() { carrier[i*4+1] as f32 } else { 128.0 }).collect();
    let mut bi = 0;
    for yi in 0..by { for xi in 0..bx {
        let mut bl = [[0.0f32;8];8];
        for r in 0..8 { for c in 0..8 { bl[r][c] = green[(yi*8+r)*w+xi*8+c]; } }
        let mut d = dct2d(&bl);
        for &(er,ec) in &EMBED_POS { if bi < bits.len() { d[er][ec] = qim_embed_s(d[er][ec], bits[bi], step); bi += 1; } }
        let o = idct2d(&d);
        for r in 0..8 { for c in 0..8 { green[(yi*8+r)*w+xi*8+c] = o[r][c]; } }
    }}
    let mut px = carrier.to_vec();
    if px.len() < w*h*4 { px.resize(w*h*4, 255); }
    for i in 0..w*h { px[i*4+1] = green[i].round().clamp(0.0, 255.0) as u8; }
    px
}

fn stego_decode_step(pixels: &[u8], w: usize, h: usize, step: f32) -> Vec<u8> {
    let bx = w/8; let by = h/8;
    let green: Vec<f32> = (0..w*h).map(|i| if i*4+1 < pixels.len() { pixels[i*4+1] as f32 } else { 128.0 }).collect();
    let mut bits = Vec::new();
    for yi in 0..by { for xi in 0..bx {
        let mut bl = [[0.0f32;8];8];
        for r in 0..8 { for c in 0..8 { bl[r][c] = green[(yi*8+r)*w+xi*8+c]; } }
        let d = dct2d(&bl);
        for &(er,ec) in &EMBED_POS { bits.push(qim_extract_s(d[er][ec], step)); }
    }}
    if bits.len() < 32*STEGO_REDUNDANCY { return Vec::new(); }
    let lb = ecc_decode(&bits, 4);
    let len = u32::from_be_bytes([lb[0],lb[1],lb[2],lb[3]]) as usize;
    let cap = (bx*by*EMBED_POS.len())/STEGO_REDUNDANCY/8;
    if len == 0 || len > cap { return Vec::new(); }
    ecc_decode(&bits[32*STEGO_REDUNDANCY..], len)
}

