/// ALife parameter search: returns JSON array of {step, fitness, jpeg_min}
pub fn alife_search(&self, carrier: &[u8], w: u32, h: u32, message: &str, generations: u32) -> String {
    let w = w as usize; let h = h as usize;
    let msg = message.as_bytes();
    let pop_size = 30usize;
    let mut pop: Vec<(f32, f64, u8)> = (0..pop_size)
        .map(|i| (5.0 + i as f32 * 195.0 / pop_size as f32, 0.0, 0))
        .collect();
    for _gen in 0..generations {
        for org in &mut pop {
            let enc = stego_encode_step(msg, carrier, w, h, org.0);
            let mut score = 0.0f64;
            let mut min_q = 0u8;
            for &q in &[95,90,85,80,75,70,65,60,55,50,45,40] {
                let comp = jpeg_simulate(&enc, w, h, q);
                if stego_decode_step(&comp, w, h, org.0) == msg {
                    score += 10.0; min_q = q;
                } else { break; }
            }
            let mse: f64 = (0..w*h).map(|i| {
                let d = carrier.get(i*4+1).copied().unwrap_or(128) as f64 - enc[i*4+1] as f64;
                d * d
            }).sum::<f64>() / (w*h) as f64;
            score -= mse * 0.1;
            org.1 = score; org.2 = min_q;
        }
        pop.sort_by(|a,b| b.1.partial_cmp(&a.1).unwrap());
        let surv: Vec<_> = pop[..pop_size/2].to_vec();
        let mut next = surv.clone();
        for i in 0..surv.len() {
            let j = (i+1) % surv.len();
            let avg = (surv[i].0 + surv[j].0) / 2.0;
            let m = ((next.len() as f32) * 0.618).sin() * 5.0;
            next.push(((avg + m).clamp(5.0, 200.0), 0.0, 0));
        }
        while next.len() < pop_size {
            let s = 5.0 + (next.len() as f32 * 7.3).sin().abs() * 195.0;
            next.push((s, 0.0, 0));
        }
        pop = next;
    }
    pop.sort_by(|a,b| b.1.partial_cmp(&a.1).unwrap());
    let top: Vec<String> = pop.iter().take(10).map(|(s,f,q)|
        format!("{{\"step\":{:.2},\"fitness\":{:.1},\"jpeg_min\":{}}}", s, f, q)
    ).collect();
    format!("[{}]", top.join(","))
}

